import { useParams, useNavigate } from "react-router-dom";

function EventDetails() {
  const { id } = useParams();
  const navigate = useNavigate();

  const events = [
    { 
      id: 1, 
      name: "Music Concert", 
      location: "Chennai", 
      date: "May 20, 2026",
      price: 999,
      description: "Enjoy a night filled with live music and entertainment.",
      image: "https://images.unsplash.com/photo-1501386761578-eac5c94b800a?w=800"
    },
    { 
      id: 2, 
      name: "Dance Show", 
      location: "Bangalore", 
      date: "June 5, 2026",
      price: 799,
      description: "Experience amazing dance performances from top artists.",
      image: "https://images.unsplash.com/photo-1551836022-d5d88e9218df?w=800"
    },
    { 
      id: 3, 
      name: "Game Party", 
      location: "Hyderabad", 
      date: "July 10, 2026",
      price: 499,
      description: "Fun gaming party with competitions and prizes.",
      image: "https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=800"
    },
    { 
      id: 4, 
      name: "Art Exhibition", 
      location: "Mumbai", 
      date: "August 15, 2026",
      price: 299,
      description: "Explore beautiful artworks from talented artists.",
      image: "https://images.unsplash.com/photo-1513364776144-60967b0f800f?w=800"
    }
  ];

  const event = events.find(e => String(e.id) === String(id));

  if (!event) {
    return (
      <h2 style={{ textAlign: "center", marginTop: "50px" }}>
        Event Not Found
      </h2>
    );
  }

  return (
    <div style={styles.container}>
      <img src={event.image} alt={event.name} style={styles.image} />

      <div style={styles.content}>
        <h1 style={styles.title}>{event.name}</h1>

        <p style={styles.description}>{event.description}</p>

        <div style={styles.details}>
          <p><strong>Date:</strong> {event.date}</p>
          <p><strong>Location:</strong> {event.location}</p>
          <p><strong>Price:</strong> ₹{event.price}</p>
        </div>

        <button
          style={styles.button}
          onClick={() => {
            alert("Event booked successfully 🎉");
            navigate("/my-bookings");
          }}
        >
          Book Now 🎟️
        </button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    maxWidth: "900px",
    margin: "40px auto",
    background: "#fff",
    borderRadius: "12px",
    overflow: "hidden",
    boxShadow: "0 6px 20px rgba(0,0,0,0.1)",
  },
  image: {
    width: "100%",
    height: "400px",
    objectFit: "cover",
  },
  content: {
    padding: "30px",
  },
  title: {
    fontSize: "32px",
    marginBottom: "10px",
  },
  description: {
    marginTop: "10px",
    lineHeight: "1.7",
    color: "#555",
  },
  details: {
    marginTop: "25px",
    fontSize: "18px",
  },
  button: {
    marginTop: "30px",
    padding: "14px 25px",
    backgroundColor: "#6C63FF",
    color: "#fff",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
    fontSize: "16px",
    fontWeight: "bold",
  },
};

export default EventDetails;
